import{_ as s,o as a,c as n,M as e}from"./chunks/framework.eac77be5.js";const F=JSON.parse('{"title":"Caveats","description":"","frontmatter":{},"headers":[],"relativePath":"caveat.md","filePath":"caveat.md"}'),o={name:"caveat.md"},t=e(`<h1 id="caveats" tabindex="-1">Caveats <a class="header-anchor" href="#caveats" aria-label="Permalink to &quot;Caveats&quot;">​</a></h1><h2 id="headings-and-links" tabindex="-1">Headings_and Links <a class="header-anchor" href="#headings-and-links" aria-label="Permalink to &quot;Headings_and Links&quot;">​</a></h2><p>In some Markdown processors (that convert Markdown into HTML), headings get unique HTML <code>id</code>s that serve as page &quot;anchors&quot;, which links can then refer to with <code>#id-of-a-heading</code>. This is exactly why we choose to use headings and links to &quot;jump&quot; within stories - it is in sync with how you jump back and forth in an HTML page.</p><h3 id="generated-anchors-in-html-documents" tabindex="-1">Generated Anchors in HTML Documents <a class="header-anchor" href="#generated-anchors-in-html-documents" aria-label="Permalink to &quot;Generated Anchors in HTML Documents&quot;">​</a></h3><p>However, in most processors, the generated <code>id</code> usually differs a bit from the actual heading. The following example is extracted from <a href="https://github.com/Flet/github-slugger" target="_blank" rel="noreferrer"><code>github-slugger</code></a>, which we use to generate our anchors:</p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">foo</span></span>
<span class="line"><span style="color:#89DDFF;">[](</span><span style="color:#F07178;text-decoration:underline;">#foo</span><span style="color:#89DDFF;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">Привет non-latin 你好</span></span>
<span class="line"><span style="color:#89DDFF;">[](</span><span style="color:#F07178;text-decoration:underline;">#привет-non-latin-你好</span><span style="color:#89DDFF;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">😄 emoji</span></span>
<span class="line"><span style="color:#89DDFF;">[](</span><span style="color:#F07178;text-decoration:underline;">#-emoji</span><span style="color:#89DDFF;">)</span></span></code></pre></div><p>It removes the quite a lot characters, but we are more interested in what gets preserved:</p><ul><li>Any letter under the <code>Letter</code> category,</li><li>Any mark under the <code>Mark</code> category,</li><li>Any normal numbers other than <a href="https://www.compart.com/en/unicode/category/No" target="_blank" rel="noreferrer">Other Numbers</a>,</li><li>All <a href="https://www.compart.com/en/unicode/category/Pc" target="_blank" rel="noreferrer">connectors punctuation</a>,</li><li>Any alphabetic characters,</li><li>The space character <code></code> (<code>0x20</code>) and hyphens <code>-</code> (<code>0x2d</code>).</li></ul><p>After that, it replaces all spaces <code></code> with hyphens.</p><h3 id="generated-anchors-in-brocatel" tabindex="-1">Generated Anchors in Brocatel <a class="header-anchor" href="#generated-anchors-in-brocatel" aria-label="Permalink to &quot;Generated Anchors in Brocatel&quot;">​</a></h3><p>I really can&#39;t remember those rules and I don&#39;t think that a system should require its users to do so. Therefor, we also transform all the links in the documents, so that users just don&#39;t need to be concerned about the charsets or any other string replacements:</p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">foo</span></span>
<span class="line"><span style="color:#89DDFF;">[](</span><span style="color:#F07178;text-decoration:underline;">#foo</span><span style="color:#89DDFF;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">Привет non-latin 你好</span></span>
<span class="line"><span style="color:#89DDFF;">[](&lt;</span><span style="color:#F07178;text-decoration:underline;">#привет non latin 你好</span><span style="color:#89DDFF;">&gt;)</span><span style="color:#A6ACCD;"> or </span><span style="color:#89DDFF;">[](</span><span style="color:#F07178;text-decoration:underline;">#привет-non-latin-你好</span><span style="color:#89DDFF;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">😄 emoji</span></span>
<span class="line"><span style="color:#89DDFF;">[](</span><span style="color:#F07178;text-decoration:underline;">#😄-emoji</span><span style="color:#89DDFF;">)</span></span></code></pre></div><p>However, it can become a problem when the user wants to use anchors in Lua code: obviously (due to how Lua recognizes its symbols) <code>a word with space</code> is treated as four separate words and it won&#39;t really serve as a symbol.</p><p>To simplify things a bit, we allow using <code>a_word_with_space</code> to refer to the <code># a word with space</code> heading. However, again, this won&#39;t work with languages with non-ASCII daily letters, and the user will need to use <code>ROOT</code>:</p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">Привет non-latin 你好</span></span>
<span class="line"><span style="color:#89DDFF;">[](</span><span style="color:#F07178;text-decoration:underline;">#привет-non-latin-你好</span><span style="color:#89DDFF;">)</span></span>
<span class="line"><span style="color:#C3E88D;">\`\`\`</span><span style="color:#A6ACCD90;">lua</span></span>
<span class="line"><span style="color:#A6ACCD;">привет_non_latin_你好 </span><span style="color:#676E95;font-style:italic;">-- Not an indentifier.</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">ROOT[</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">привет-non-latin-你好</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">] </span><span style="color:#676E95;font-style:italic;">-- This somehow works.</span></span>
<span class="line"><span style="color:#C3E88D;">\`\`\`</span></span></code></pre></div><p>Here comes a third caveat: Lua has poor regex and Unicode support, which means, it is hard to keep compiler rules (TypeScript) and runtime rules (Lua) in sync:</p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">你好，世界！</span></span>
<span class="line"><span style="color:#89DDFF;">[](</span><span style="color:#F07178;text-decoration:underline;">#你好世界</span><span style="color:#89DDFF;">)</span><span style="color:#A6ACCD;"> or </span><span style="color:#89DDFF;">[](</span><span style="color:#F07178;text-decoration:underline;">#你好，世界！</span><span style="color:#89DDFF;">)</span></span>
<span class="line"><span style="color:#C3E88D;">\`\`\`</span><span style="color:#A6ACCD90;">lua</span></span>
<span class="line"><span style="color:#A6ACCD;">ROOT[</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">你好世界</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">]      </span><span style="color:#676E95;font-style:italic;">-- This works.</span></span>
<span class="line"><span style="color:#A6ACCD;">ROOT[</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">你好，世界！</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">]  </span><span style="color:#676E95;font-style:italic;">-- This does not.</span></span>
<span class="line"><span style="color:#C3E88D;">\`\`\`</span></span></code></pre></div>`,17),l=[t];function r(p,c,i,d,h,y){return a(),n("div",null,l)}const D=s(o,[["render",r]]);export{F as __pageData,D as default};
